if (! function_exists('text_complexity_analyzer')) {
    function text_complexity_analyzer($text)
    {
        $text = trim($text);
        if (empty($text)) return json_encode(['error' => 'Text is required']);
        // Count sentences, words, chars, syllables
        $sentences = preg_split('/[.!?]+/', $text, -1, PREG_SPLIT_NO_EMPTY);
        $sentenceCount = count($sentences);
        // Count words (alphanumeric sequences)
        preg_match_all('/[a-zA-Z]+/', $text, $wordMatches);
        $words = $wordMatches[0];
        $wordCount = count($words);
        $charCount = strlen($text);
        $letterCount = strlen(preg_replace('/[^a-zA-Z]/', '', $text));
        // Syllable counting heuristic
        $countSyllables = function($word) {
            $word = strtolower($word);
            $word = preg_replace('/e$/', '', $word);
            $word = preg_replace('/es$/', '', $word);
            $word = preg_replace('/ed$/', '', $word);
            preg_match_all('/[aeiouy]+/', $word, $matches);
            $count = count($matches[0]);
            return max(1, $count);
        };
        $totalSyllables = 0;
        foreach ($words as $w) $totalSyllables += $countSyllables($w);
        // Long words (3+ syllables)
        $longWords = 0;
        foreach ($words as $w) { if ($countSyllables($w) >= 3) $longWords++; }
        // Averages
        $avgSyllablesPerWord = $wordCount > 0 ? $totalSyllables / $wordCount : 0;
        $avgWordsPerSentence = $sentenceCount > 0 ? $wordCount / $sentenceCount : 0;
        $avgCharsPerWord = $wordCount > 0 ? $letterCount / $wordCount : 0;
        // Flesch Reading Ease
        $flesch = 0;
        if ($wordCount > 0 && $sentenceCount > 0) {
            $flesch = 206.835 - 1.015 * ($wordCount / $sentenceCount) - 84.6 * ($totalSyllables / $wordCount);
            $flesch = max(0, min(100, round($flesch, 1)));
        }
        // Flesch-Kincaid Grade Level
        $fkGrade = 0;
        if ($wordCount > 0 && $sentenceCount > 0) {
            $fkGrade = 0.39 * ($wordCount / $sentenceCount) + 11.8 * ($totalSyllables / $wordCount) - 15.59;
            $fkGrade = max(0, round($fkGrade, 1));
        }
        // Readability interpretation
        $interpretation = 'Very easy to read (approx. 5th grade)';
        if ($flesch < 10) $interpretation = 'Extremely difficult (college graduate)';
        elseif ($flesch < 30) $interpretation = 'Very difficult (college level)';
        elseif ($flesch < 50) $interpretation = 'Difficult (high school)';
        elseif ($flesch < 60) $interpretation = 'Fairly difficult (10th-12th grade)';
        elseif ($flesch < 70) $interpretation = 'Standard (8th-9th grade)';
        elseif ($flesch < 80) $interpretation = 'Fairly easy (7th grade)';
        elseif ($flesch < 90) $interpretation = 'Easy (6th grade)';
        return json_encode([
            'characters' => $charCount,
            'letters' => $letterCount,
            'words' => $wordCount,
            'sentences' => $sentenceCount,
